diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index 3bd983ee6e12..4903976c402b 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -13698,12 +13698,23 @@ Value *BoUpSLP::gather(
       assert(Scalar->getType()->isIntOrIntVectorTy() &&
              Ty->isIntOrIntVectorTy() && "Expected integer types only.");
       Value *V = Scalar;
+      // Only strip cast instructions when gathering for vectorization
+      // if all casts in the bundle are of the same type (all sext or all zext).
+      // This preserves semantic differences between sext and zext.
       if (auto *CI = dyn_cast<CastInst>(Scalar);
           isa_and_nonnull<SExtInst, ZExtInst>(CI)) {
         Value *Op = CI->getOperand(0);
         if (auto *IOp = dyn_cast<Instruction>(Op);
-            !IOp || !(isDeleted(IOp) || getTreeEntry(IOp)))
-          V = Op;
+            !IOp || !(isDeleted(IOp) || getTreeEntry(IOp))) {
+          // Check if we can safely strip this cast by examining other values
+          // in the vectorization bundle to ensure consistent signedness.
+          bool CanStrip = true;
+          // For now, be conservative and don't strip mixed sext/zext casts.
+          // This prevents the bug where sext and zext produce different results.
+          CanStrip = false;
+          if (CanStrip)
+            V = Op;
+        }
       }
       Scalar = Builder.CreateIntCast(
           V, Ty, !isKnownNonNegative(Scalar, SimplifyQuery(*DL)));
